import sysfrom selenium import webdriverfrom selenium.webdriver.common.by import Byfrom selenium.webdriver.chrome.service import Servicefrom selenium.webdriver.chrome.options import Optionsfrom webdriver_manager.chrome import ChromeDriverManagerprint("Python utilisé dans le test :", sys.executable)# Récupérer les argumentstry:    browser = sys.argv[1]    environment = sys.argv[2]except IndexError:    print("❌ Veuillez fournir le navigateur et l'environnement en arguments.")    sys.exit(1)# URL selon environnementenv_urls = {    "dev": "https://flightpass.royalairmaroc.com/realms/flightpass/login-actions/registration?client_id=ram-flightpass-back&tab_id=D0IUVWtqbg0&client_data=eyJydSI6Imh0dHBzOi8vZmxpZ2h0cGFzcy5yb3lhbGFpcm1hcm9jLmNvbS9sb2dpbi9vYXV0aDIvY29kZS9rZXljbG9hayIsInJ0IjoiY29kZSIsInN0IjoiMlJuZUxfNzFaY09ZRXNoTVdjc1c1Yk1fQkMzaERsaEFXcTBPc3J2aF9mdz0ifQ&ui_locales=fr",    "staging": "https://staging.example.com",    "production": "https://example.com"}# Vérifie si l'environnement est valideif environment not in env_urls:    print("❌ Environnement invalide.")    sys.exit(1)# Initialiser le navigateurif browser == "chrome":    options = Options()    service = Service(ChromeDriverManager().install())    driver = webdriver.Chrome(service=service, options=options)else:    print("❌ Navigateur non supporté (seul Chrome est géré ici).")    sys.exit(1)# Ouvrir l'URLdriver.get(env_urls[environment])print("✅ Titre de la page :", driver.title)driver.quit()